function ShapeSVG({shape,formula,angle}){const f=formula||"?",a=angle||"";const S={fill:"none",stroke:C.green,strokeWidth:2};const T={fill:C.text,fontSize:12,fontWeight:600,fontFamily:"'DM Sans',sans-serif",textAnchor:"middle"};const L={fill:C.textMuted,fontSize:10,fontFamily:"'DM Sans',sans-serif",textAnchor:"middle"};const LP={fill:"none",stroke:C.amber,strokeWidth:1.5,strokeDasharray:"3,2"};const Lb={fill:C.green,fontSize:11,fontWeight:500,fontFamily:"'DM Sans',sans-serif",textAnchor:"middle"};const wrap=(ch,vb="0 0 200 180")=>(<div style={{background:C.bgLight,border:`1px solid ${C.border}`,borderRadius:10,padding:"14px 10px 8px",margin:"10px 0",textAlign:"center"}}><svg viewBox={vb} style={{width:"100%",maxWidth:230,display:"block",margin:"0 auto"}}>{ch}</svg></div>);if(shape==="tetrahedral")return wrap(<><circle cx="100" cy="78" r="15" fill={C.bgCard} {...S}/><text x="100" y="83" {...T}>C</text><line x1="100" y1="63" x2="100" y2="20" {...S}/><text x="100" y="14" {...L}>H</text><line x1="115" y1="78" x2="172" y2="58" {...S}/><text x="180" y="62" {...L}>H</text><line x1="88" y1="91" x2="42" y2="138" {...S}/><text x="30" y="148" {...L}>H</text><line x1="112" y1="91" x2="158" y2="138" {...S}/><text x="170" y="148" {...L}>H</text><path d="M132,125 A38,38 0 0,0 152,100" fill="none" stroke={C.textDim} strokeWidth="1" strokeDasharray="3,2"/><text x="155" y="118" fill={C.textMuted} fontSize="9" fontFamily="'DM Sans',sans-serif">{a}</text><text x="100" y="172" {...Lb}>{f} — Tetrahedral</text></>);if(shape==="pyramidal")return wrap(<><circle cx="100" cy="82" r="15" fill={C.bgCard} {...S}/><text x="100" y="87" {...T}>N</text><line x1="100" y1="67" x2="100" y2="28" {...S}/><text x="100" y="22" {...L}>H</text><line x1="87" y1="94" x2="38" y2="142" {...S}/><text x="26" y="152" {...L}>H</text><line x1="113" y1="94" x2="162" y2="142" {...S}/><text x="174" y="152" {...L}>H</text><ellipse cx="100" cy="60" rx="7" ry="4" {...LP}/><ellipse cx="100" cy="55" rx="7" ry="4" {...LP}/><text x="122" y="52" fill={C.amber} fontSize="8" fontFamily="'DM Sans',sans-serif">lone pair</text><text x="100" y="172" {...Lb}>{f} — Pyramidal ({a})</text></>);if(shape==="bent")return wrap(<><circle cx="100" cy="65" r="15" fill={C.bgCard} {...S}/><text x="100" y="70" {...T}>O</text><line x1="87" y1="77" x2="38" y2="125" {...S}/><text x="26" y="135" {...L}>H</text><line x1="113" y1="77" x2="162" y2="125" {...S}/><text x="174" y="135" {...L}>H</text><ellipse cx="86" cy="50" rx="7" ry="4" {...LP}/><ellipse cx="86" cy="45" rx="7" ry="4" {...LP}/><ellipse cx="114" cy="50" rx="7" ry="4" {...LP}/><ellipse cx="114" cy="45" rx="7" ry="4" {...LP}/><text x="100" y="36" fill={C.amber} fontSize="8" fontFamily="'DM Sans',sans-serif">2 lone pairs</text><path d="M56,112 A45,45 0 0,0 78,90" fill="none" stroke={C.textDim} strokeWidth="1" strokeDasharray="3,2"/><text x="46" y="96" fill={C.textMuted} fontSize="9" fontFamily="'DM Sans',sans-serif">{a}</text><text x="100" y="160" {...Lb}>{f} — Bent ({a})</text></>,"0 0 200 165");if(shape==="trigonal_planar")return wrap(<><circle cx="100" cy="78" r="15" fill={C.bgCard} {...S}/><text x="100" y="83" {...T}>B</text><line x1="100" y1="63" x2="100" y2="20" {...S}/><text x="100" y="14" {...L}>F</text><line x1="87" y1="91" x2="38" y2="140" {...S}/><text x="26" y="150" {...L}>F</text><line x1="113" y1="91" x2="162" y2="140" {...S}/><text x="174" y="150" {...L}>F</text><text x="100" y="172" {...Lb}>{f} — Trigonal planar ({a})</text></>);if(shape==="linear")return wrap(<><circle cx="110" cy="35" r="14" fill={C.bgCard} {...S}/><text x="110" y="40" {...T}>C</text><line x1="96" y1="35" x2="30" y2="35" {...S}/><line x1="93" y1="31" x2="33" y2="31" {...S}/><line x1="124" y1="35" x2="190" y2="35" {...S}/><line x1="127" y1="31" x2="187" y2="31" {...S}/><text x="18" y="40" {...L}>O</text><text x="202" y="40" {...L}>O</text><text x="110" y="68" {...Lb}>{f} — Linear ({a})</text></>,"0 0 220 75");if(shape==="octahedral")return wrap(<><circle cx="100" cy="90" r="14" fill={C.bgCard} {...S}/><text x="100" y="95" {...T}>S</text><line x1="100" y1="76" x2="100" y2="22" {...S}/><text x="100" y="16" {...L}>F</text><line x1="100" y1="104" x2="100" y2="158" {...S}/><text x="100" y="170" {...L}>F</text><line x1="86" y1="90" x2="22" y2="90" {...S}/><text x="12" y="94" {...L}>F</text><line x1="114" y1="90" x2="178" y2="90" {...S}/><text x="188" y="94" {...L}>F</text><line x1="110" y1="80" x2="150" y2="42" stroke={C.green} strokeWidth="1.5" strokeDasharray="4,3"/><text x="158" y="40" fill={C.textMuted} fontSize="9">F</text><line x1="90" y1="100" x2="50" y2="138" stroke={C.green} strokeWidth="1.5" strokeDasharray="4,3"/><text x="42" y="148" fill={C.textMuted} fontSize="9">F</text><text x="100" y="186" {...Lb}>{f} — Octahedral ({a})</text></>,"0 0 200 192");return <div style={{color:C.textMuted,fontSize:12,padding:8,background:C.bgLight,borderRadius:8,margin:"6px 0"}}>Shape: {shape} {f} {a}</div>;}

/* ═══ MECHANISM DIAGRAM ═══ */
function MechDiagram({type,equation}){const isFR=type==="free_radical";const step=(c)=>({color:c,fontSize:11,fontWeight:600,fontFamily:"'DM Sans',sans-serif",marginTop:8,marginBottom:2});const line={color:C.text,fontSize:13,fontFamily:"'JetBrains Mono',monospace",lineHeight:1.9};const dot=<span style={{color:C.red,fontWeight:700}}>•</span>;const arr=(c)=><span style={{color:c||C.green}}> → </span>;return(<div style={{background:C.bgLight,border:`1px solid ${C.border}`,borderRadius:10,padding:"14px 18px",margin:"10px 0"}}><div style={{fontSize:10,textTransform:"uppercase",letterSpacing:"0.1em",color:C.green,marginBottom:6,fontFamily:"'DM Sans',sans-serif",fontWeight:600}}>{isFR?"Free Radical Substitution":"Electrophilic Addition"}</div><div style={line}>{isFR?(<><div style={step(C.amber)}>Initiation — homolytic fission (UV light)</div><div>Cl—Cl {arr(C.amber)} 2Cl{dot}</div><div style={step(C.green)}>Propagation — chain reaction</div><div>Cl{dot} + CH₄ {arr()} CH₃{dot} + HCl</div><div>CH₃{dot} + Cl₂ {arr()} CH₃Cl + Cl{dot}</div><div style={step(C.textMuted)}>Termination — radicals combine</div><div>2Cl{dot} {arr(C.textMuted)} Cl₂</div><div>Cl{dot} + CH₃{dot} {arr(C.textMuted)} CH₃Cl</div><div>2CH₃{dot} {arr(C.textMuted)} C₂H₆</div></>):(<><div style={step(C.green)}>Step 1 — π bond attacks electrophile</div><svg viewBox="0 0 280 55" style={{width:"100%",maxWidth:280,display:"block",margin:"4px 0"}}><text x="5" y="30" fill={C.text} fontSize="13" fontFamily="'JetBrains Mono',monospace">C=C</text><path d="M42,25 Q80,5 118,20" fill="none" stroke={C.amber} strokeWidth="2" markerEnd="url(#ca)"/><defs><marker id="ca" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="5" markerHeight="5" orient="auto"><path d="M0,2 L10,5 L0,8 z" fill={C.amber}/></marker></defs><text x="55" y="12" fill={C.amber} fontSize="9" fontFamily="'DM Sans',sans-serif">curly arrow</text><text x="122" y="30" fill={C.text} fontSize="13" fontFamily="'JetBrains Mono',monospace">H—Br</text><text x="122" y="48" fill={C.textMuted} fontSize="9" fontFamily="'DM Sans',sans-serif">δ⁺    δ⁻</text></svg><div>C=C + H<sup>δ⁺</sup>—Br<sup>δ⁻</sup> {arr()} C—C⁺ + Br⁻</div><div style={step(C.green)}>Step 2 — Nucleophilic attack</div><div>Br⁻ {arr()} C⁺ (attacks carbocation)</div><div style={{marginTop:8,color:C.green,fontSize:12}}>Overall: {equation}</div></>)}</div></div>);}

function EqBox({content}){return(<div style={{background:C.bgLight,border:`1px solid ${C.greenBorder}`,borderRadius:8,padding:"8px 16px",margin:"6px 0",display:"inline-block",fontFamily:"'JetBrains Mono',monospace",fontSize:15,fontWeight:500,color:C.green}}>{content}</div>);}
function ConfigBox({element,config}){return(<div style={{background:C.bgLight,border:`1px solid ${C.border}`,borderRadius:8,padding:"8px 14px",margin:"6px 0",display:"inline-block"}}><span style={{color:C.amber,fontWeight:600,fontSize:14,fontFamily:"'DM Sans',sans-serif"}}>{element}: </span><span style={{fontFamily:"'JetBrains Mono',monospace",fontSize:14,color:C.green}}>{config}</span></div>);}

/* ═══ PARSER ═══ */
function parseAndRender(text){
  const lines=text.split("\n");
  const elements=[];
  const tagRe=/^\[(\w+):(.+)\]$/;
  for(let i=0;i<lines.length;i++){
    const line=lines[i].trim();
    const m=line.match(tagRe);
    if(m){
      const[,tag,params]=m;
      const p=params.split(":");
      if(tag==="SHAPE")elements.push(<ShapeSVG key={`s${i}`} shape={p[0]} formula={p[1]} angle={p[2]}/>);
      else if(tag==="MECHANISM")elements.push(<MechDiagram key={`m${i}`} type={p[0]} equation={p.slice(1).join(":")}/>);
      else if(tag==="EQUATION")elements.push(<EqBox key={`e${i}`} content={p.join(":")}/>);
      else if(tag==="CONFIG")elements.push(<ConfigBox key={`c${i}`} element={p[0]} config={p.slice(1).join(":")}/>);
    } else if(line.startsWith("## ")){
      elements.push(<div key={`h${i}`} style={{fontSize:15,fontWeight:600,color:C.text,fontFamily:"'DM Serif Display',serif",marginTop:16,marginBottom:6,paddingBottom:6,borderBottom:`1px solid ${C.border}`}}>{line.slice(3)}</div>);
    } else if(line.startsWith("### ")){
      elements.push(<div key={`h3${i}`} style={{fontSize:13,fontWeight:600,color:C.green,marginTop:12,marginBottom:4,letterSpacing:"0.03em"}}>{line.slice(4)}</div>);
    } else if(line.match(/^\d+\.\s/)){
      const num=line.match(/^(\d+)\.\s(.+)/);
      if(num) elements.push(<div key={`ol${i}`} style={{display:"flex",gap:10,marginBottom:4,paddingLeft:4}}><span style={{color:C.green,fontWeight:600,fontSize:13,flexShrink:0,minWidth:20}}>{num[1]}.</span><span style={{fontSize:13.5,lineHeight:1.7}}><RichLine text={num[2]}/></span></div>);
    } else if(line.startsWith("- ")||line.startsWith("• ")){
      elements.push(<div key={`li${i}`} style={{display:"flex",gap:10,marginBottom:3,paddingLeft:4}}><span style={{color:C.green,fontSize:10,marginTop:7,flexShrink:0}}>●</span><span style={{fontSize:13.5,lineHeight:1.7}}><RichLine text={line.slice(2)}/></span></div>);
    } else if(line){
      elements.push(<div key={`t${i}`} style={{marginBottom:6,fontSize:13.5,lineHeight:1.8}}><RichLine text={line}/></div>);
    } else {
      elements.push(<div key={`sp${i}`} style={{height:8}}/>);
    }
  }
  return elements;
}
function RichLine({text}){return text.split(/(\*\*.*?\*\*|\*.*?\*|`[^`]+`)/g).map((s,i)=>{if(!s)return null;if(s.startsWith("**")&&s.endsWith("**"))return <strong key={i} style={{fontWeight:600,color:C.text}}>{s.slice(2,-2)}</strong>;if(s.startsWith("*")&&s.endsWith("*"))return <em key={i} style={{fontStyle:"italic",color:C.text}}>{s.slice(1,-1)}</em>;if(s.startsWith("`")&&s.endsWith("`"))return <code key={i} style={{background:C.greenDim,padding:"2px 7px",borderRadius:4,fontFamily:"'JetBrains Mono',monospace",fontSize:"0.85em",color:C.green,border:`1px solid ${C.greenBorder}`}}>{s.slice(1,-1)}</code>;return <span key={i}>{s}</span>;});}

